// ── Mulberry32 PRNG — identical to client-side implementation ──────────────────
function mulberry32(seed: number) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function getSelectedQuestionIds(tier: number, seed: number): string[] {
  const pool = [...(TIER_IDS[tier] ?? [])];
  const rand = mulberry32(seed);
  for (let i = pool.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1));
    [pool[i], pool[j]] = [pool[j], pool[i]];
  }
  return pool.slice(0, 10);
}

function calcKarmaDelta(score: number, tier: number): number {
  const pct = score / 10;
  if (pct >= 0.9) return parseFloat((tier * 0.05).toFixed(2));
  if (pct >= 0.6) return parseFloat((tier * 0.02).toFixed(2));
  return -0.1;
}

// ── Handler ────────────────────────────────────────────────────────────────────

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, {
      headers: {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "POST, OPTIONS",
        "Access-Control-Allow-Headers": "Authorization, Content-Type",
      },
    });
  }

  try {
    // Authenticate the request
    const authHeader = req.headers.get("Authorization");
    if (!authHeader?.startsWith("Bearer ")) {
      return jsonError("Unauthorized", 401);
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const anonKey = Deno.env.get("SUPABASE_ANON_KEY")!;

    // Verify the user JWT using the anon client
    const userClient = createClient(supabaseUrl, anonKey, {
      global: { headers: { Authorization: authHeader } },
    });
    const { data: { user }, error: authError } = await userClient.auth.getUser();
    if (authError || !user) return jsonError("Unauthorized", 401);

    // Parse body
    const body = await req.json();
    const { tier, seed, answers } = body as {
      tier: number;
      seed: number;
      answers: Record<string, number>; // "0"–"9" → option index
    };

    if (
      typeof tier !== "number" || tier < 1 || tier > 20 ||
      typeof seed !== "number" ||
      typeof answers !== "object"
    ) {
      return jsonError("Invalid payload", 400);
    }

    // Reconstruct the exact 10 questions the user saw (same PRNG, same order)
    const selectedIds = getSelectedQuestionIds(tier, seed);
    const total = selectedIds.length;

    // Score server-side — correct_answer never left the server
    let score = 0;
    const reviews: Array<{ questionId: string; correctAnswer: number; explanation: string }> = [];
    for (let i = 0; i < total; i++) {
      const qId = selectedIds[i];
      const correct = ANSWER_KEY[qId] ?? -1;
      const given = answers[String(i)];
      if (given === correct) score++;
      reviews.push({ questionId: qId, correctAnswer: correct, explanation: EXPLANATIONS[qId] ?? "" });
    }

    const karmaChange = calcKarmaDelta(score, tier);

    // Persist to DB using service role (bypasses RLS user check since we've verified JWT above)
    const adminClient = createClient(supabaseUrl, serviceKey);
    const { error: dbError } = await adminClient
      .from("test_completions")
      .upsert(
        {
          user_id: user.id,
          tier,
          score,
          total,
          karma_change: karmaChange,
          completed_at: new Date().toISOString(),
        },
        { onConflict: "user_id,tier" }
      );

    if (dbError) {
      console.error("test_completions upsert:", dbError.message);
      // Don't fail the request — return results even if DB write fails
    }

    return new Response(
      JSON.stringify({ score, total, karmaChange, reviews }),
      {
        headers: {
          "Content-Type": "application/json",
          "Access-Control-Allow-Origin": "*",
        },
      }
    );
  } catch (err) {
    console.error("score-test error:", err);
    return jsonError("Internal server error", 500);
  }
});

function jsonError(message: string, status: number) {
  return new Response(JSON.stringify({ error: message }), {
    status,
    headers: { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" },
  });
}
